"use strict";(self.webpackChunktu_cis_4398_docs_template=self.webpackChunktu_cis_4398_docs_template||[]).push([["5996"],{47540:function(e){e.exports=JSON.parse('{"project":{"title":"Hip.io","description":"Hip.io is a reimagined online multiplayer version of Hungry Hungry Hippo designed for children who use Augmentative and Alternative Communication (AAC) devices. Unlike traditional games, the AAC user leads gameplay by selecting which foods appear and applying special effects, while other players control hippos to catch the chosen foods. The system uses React for the UI, Phaser for game logic, and a WebSocket server for real-time multiplayer synchronization. The goal is to empower AAC users to direct group play, making fast-paced games more accessible and inclusive.","website":"https://project-acc-hungry-hippos.vercel.app/","documentation":"https://capstone-projects-2025-spring.github.io/project-acc-hungry-hippos","demo":"https://www.youtube.com/watch?v=tA-bBxNLHKY&t=2526","source":"https://github.com/Capstone-Projects-2025-Spring/project-acc-hungry-hippos","tags":["game","accessibility","multiplayer","aac","research"],"semester":"Summer 2025","slug":"hip-io","members":["Arvindh Velrajan","Mohammed Karim","Kostandin Jorgji","Jasmine Liu","Omais Khan"],"useDocsAsPreview":true},"routeSlug":"hip-io-jasmine-liu","canonicalSlug":"hip-io"}')}}]);